const [isSyncing, setIsSyncing] = useState(false)  // State for transfer status tracking
const [spotifyPlaylistId, setSpotifyPlaylistId] = useState('') // Source playlist identifier
const [targetName, setTargetName] = useState('My Premium Sync') // Custom destination playlist name
const [transferStatus, setTransferStatus] = useState<string | null>(null) // Feedback status for users

// Function to execute the backend transfer process
const handleTransfer = async () => {
  if (!spotifyPlaylistId) {
      alert("Please enter a Spotify Playlist ID to begin the migration.");
      return;
  }

  setIsSyncing(true); // Show progress in the UI
  setTransferStatus("Initiating sync engine..."); // Status update for feedback

  try {
    const response = await fetch('http://localhost:8000/transfer', { // API request to our FastAPI backend
      method: 'POST', // Use POST method for sending data
      headers: { 'Content-Type': 'application/json' }, // Specify JSON format
      body: JSON.stringify({ // Payload with source and destination details
        spotify_playlist_id: spotifyPlaylistId,
        target_playlist_name: targetName
      })
    });

    const data = await response.json(); // Parse the server's response

    if (response.ok) { // Check for successful transfer execution
      setTransferStatus(`Success! Moved ${data.tracks_moved} tracks with surgical precision.`); // Show success message
    } else { // Handle server-side errors
      setTransferStatus(`Error: ${data.detail || 'The migration failed.'}`); // Display failure details
    }
  } catch (error) { // Catch network and unexpected front-end errors
    setTransferStatus("Failed to reach the sync server. Please try again."); // Connection failure feedback
  } finally {
    setIsSyncing(false); // Stop the sync visual indicator
  }
};

