import { useState, useEffect } from 'react'; // Import React hooks for state and side effects
import './App.css'; // Import custom Vanilla CSS for glassmorphism styling

function App() { // Main Weather Dashboard application component
  const [city, setCity] = useState('Lagos'); // State to track the currently searched city
  const [weatherData, setWeatherData] = useState<any>(null); // State to store real-time weather information
  const [forecastData, setForecastData] = useState<any>(null); // State to store the 5-day weather forecast
  const [newsData, setNewsData] = useState<any[]>([]); // State to store the curated news articles
  const [exchangeData, setExchangeData] = useState<any>(null); // State to store the current currency exchange rates
  const [loading, setLoading] = useState(true); // State to manage the global loading indicator
  const [error, setError] = useState<string | null>(null); // State to capture and display any API errors

  // Core function to fetch all dashboard data from our FastAPI backend
  const fetchDashboardData = async (targetCity: string) => { // Async fetch logic for the dashboard
    setLoading(true); // Show the loading state while data is in flight
    setError(null); // Clear any previous error messages before retrying
    try { // Begin the multi-endpoint data retrieval process
      // Execute all API requests in parallel for maximum speed and efficiency
      const [weatherRes, forecastRes, newsRes, exchangeRes] = await Promise.all([
        fetch(`http://localhost:8000/weather?city=${targetCity}`), // Fetch current conditions
        fetch(`http://localhost:8000/forecast?city=${targetCity}`), // Fetch extended forecast
        fetch(`http://localhost:8000/news`), // Fetch general news stories
        fetch(`http://localhost:8000/exchange-rate?base=USD`) // Fetch global currency rates
      ]);

      // Parse the JSON responses from each successfully completed request
      const weather = await weatherRes.json(); // Decode weather JSON
      const forecast = await forecastRes.json(); // Decode forecast JSON
      const news = await newsRes.json(); // Decode news JSON
      const exchange = await exchangeRes.json(); // Decode exchange JSON

      // Update the application state with the fresh data from the server
      setWeatherData(weather); // Persist weather to state
      setForecastData(forecast); // Persist forecast to state
      setNewsData(news.articles?.slice(0, 5) || []); // Persist top 5 news stories
      setExchangeData(exchange); // Persist rates to state
    } catch (err) { // Handle network timeouts or backend server failures
      setError("Failed to synchronize with the weather server. Please try again."); // Notify the user
    } finally { // Always execute cleanup regardless of success or failure
      setLoading(false); // Remove the loading overlay from the UI
    }
  }; // End of fetchDashboardData function

  // Trigger the initial data load when the component first mounts to the DOM
  useEffect(() => { // Standard React effect hook for initialization
    fetchDashboardData(city); // Request data for the default city (Lagos)
  }, []); // Empty dependency array ensures this only runs once on startup

  // Handler for the search form submission to look up new locations
  const handleSearch = (e: React.FormEvent) => { // Event handler for city search
    e.preventDefault(); // Prevent the browser's default form submission behavior
    if (city.trim()) { // Only proceed if the user entered a non-empty string
      fetchDashboardData(city); // Execute a new fetch for the specified location
    }
  }; // End of handleSearch handler

  // Helper function to extract a high-level summary of the current conditions
  const getWeatherIcon = (description: string) => { // Dynamic icon mapping based on weather description
    const desc = description.toLowerCase(); // Standardize input for consistent matching
    if (desc.includes('cloud')) return '☁️'; // Cloud icon for overcast skies
    if (desc.includes('rain')) return '🌧️'; // Rain icon for precipitation
    if (desc.includes('clear')) return '☀️'; // Sun icon for clear weather
    if (desc.includes('storm')) return '⛈️'; // Storm icon for thunder
    return '⛅'; // Default cloud-sun icon for mixed conditions
  }; // End of icon helper

  if (loading) return <div className="loader-overlay">Refreshing Atmos...</div>; // Render loading screen during boot

  return ( // Start of the main application JSX layout
    <div className="dashboard-root"> {/* Main container for the glassmorphism theme */}

      {/* Search Header: Top navigation area for city lookup and branding */}
      <header className="glass-header"> {/* Floating header with blur effect */}
        <h1 className="logo-text">AtmosSync</h1> {/* Application name branding */}
        <form onSubmit={handleSearch} className="search-bar"> {/* Search input container */}
          <input 
            type="text" 
            placeholder="Search location..." 
            value={city} 
            onChange={(e) => setCity(e.target.value)} // Bind input value to React state
            className="glass-input" 
          /> {/* Search text field */}
          <button type="submit" className="glass-button">Update</button> {/* Search submission button */}
        </form> {/* End of search form */}
      </header> {/* End of header section */}

      <main className="bento-grid"> {/* Responsive grid layout for dashboard components */}

        {/* Current Weather Card: Reverted to its original clean hero layout for temperature and conditions */}
        {weatherData && ( // Check for weather data before rendering the primary hero card
          <section className="glass-card main-weather-card"> {/* Large hero card for current weather conditions */}
            <div className="weather-hero"> {/* Container for the high-impact temperature and icon display */}
              <span className="big-icon">{getWeatherIcon(weatherData.weather[0].description)}</span> {/* Main weather emoji icon */}
              <div className="temp-info"> {/* Container for text-based temperature information */}
                <h2 className="current-temp">{Math.round(weatherData.main.temp)}°</h2> {/* Large rounded temperature display */}
                <p className="weather-desc">{weatherData.weather[0].description}</p> {/* Verbal description of the sky */}
              </div> {/* End of temperature info block */}
            </div> {/* End of weather hero section */}
            <div className="weather-stats"> {/* Original row for humidity, wind, and pressure statistics */}
              <div className="stat"><span>Humidity</span><strong>{weatherData.main.humidity}%</strong></div> {/* Humidity percentage display */}
              <div className="stat"><span>Wind</span><strong>{weatherData.wind.speed} m/s</strong></div> {/* Wind speed metric display */}
              <div className="stat"><span>Pressure</span><strong>{weatherData.main.pressure} hPa</strong></div> {/* Air pressure metric display */}
            </div> {/* End of weather stats row */}
          </section> // End of original-style weather hero card
        )}

        {/* Forecast Card: Retains its original position in the top-right of the bento grid */}
        <section className="glass-card forecast-card"> {/* Card container for future weather outlook */}
          <h3 className="section-title">5-Day Forecast</h3> {/* Section heading for the forecast */}
          <div className="forecast-scroll"> {/* Flexbox container for horizontal weather items */}
            {forecastData?.list?.slice(0, 5).map((item: any, idx: number) => ( // Map through the first 5 forecast points
              <div key={idx} className="forecast-item"> {/* Individual column for a forecast time slot */}
                <span className="forecast-time">{new Date(item.dt * 1000).getHours()}:00</span> {/* Hour of the forecast */}
                <span className="forecast-icon">{getWeatherIcon(item.weather[0].description)}</span> {/* Forecast weather icon */}
                <span className="forecast-temp">{Math.round(item.main.temp)}°</span> {/* Predicted temperature for the time */}
              </div> // End of forecast column
            ))}
          </div> {/* End of scroll container */}
        </section> {/* End of forecast section */}

        {/* New Celestial Hub Card: Added as a separate bento module to keep the weather card clean */}
        {weatherData?.astro && ( // Render only if astronomical data was successfully calculated
          <section className="glass-card astro-card"> {/* Dedicated card for sunrise, sunset, and lunar info */}
            <h3 className="section-title">Celestial Hub</h3> {/* Heading for the astronomical section */}
            <div className="astro-grid"> {/* Grid container for solar and lunar metrics */}
              <div className="astro-row"> {/* Row for sunrise data */}
                <span className="material-symbols-outlined">sunrise</span> {/* Sunrise graphic icon */}
                <span>Rise: <strong>{weatherData.astro.sunrise}</strong></span> {/* Formatted sunrise time */}
              </div> {/* End of sunrise row */}
              <div className="astro-row"> {/* Row for sunset data */}
                <span className="material-symbols-outlined">sunset</span> {/* Sunset graphic icon */}
                <span>Set: <strong>{weatherData.astro.sunset}</strong></span> {/* Formatted sunset time */}
              </div> {/* End of sunset row */}
              <div className="moon-narrative"> {/* Container for the descriptive lunar status text */}
                <p>{weatherData.astro.moon_status}</p> {/* Narrative moon phase and position text */}
              </div> {/* End of moon narrative block */}
            </div> {/* End of celestial grid */}
          </section> // End of the new Celestial Hub bento card
        )}

        {/* Financial Card: Remains in the second row of the bento grid */}
        {exchangeData && ( // Conditional render for currency conversion data
          <section className="glass-card exchange-card"> {/* Bento card for currency exchange rates */}
            <h3 className="section-title">Currency Hub</h3> {/* Section heading for finance */}
            <div className="exchange-list"> {/* Vertical list container for currency pairs */}
              <div className="currency-row"><span>NGN</span><strong>₦{exchangeData.conversion_rates.NGN.toFixed(2)}</strong></div> {/* USD to Naira rate */}
              <div className="currency-row"><span>EUR</span><strong>€{exchangeData.conversion_rates.EUR.toFixed(3)}</strong></div> {/* USD to Euro rate */}
              <div className="currency-row"><span>GBP</span><strong>£{exchangeData.conversion_rates.GBP.toFixed(3)}</strong></div> {/* USD to Pound rate */}
            </div> {/* End of exchange list */}
          </section> // End of financial section
        )}

        {/* News Feed Card: Adjusted span to fit into the new 3-column second row layout */}
        <section className="glass-card news-card"> {/* Bento card for aggregated world news */}
          <h3 className="section-title">World Intel</h3> {/* Section heading for news stories */}
          <div className="news-feed"> {/* Vertical feed for curated news headlines */}
            {newsData.map((article, idx) => ( // Map through the top news articles from state
              <div key={idx} className="news-item"> {/* Individual news entry with title and source */}
                <p className="news-title">{article.title}</p> {/* Article headline text */}
                <span className="news-source">{article.source.name}</span> {/* Name of the news publisher */}
              </div> // End of news entry
            ))}
          </div> {/* End of news feed container */}
        </section> {/* End of news section */}

      </main> {/* End of bento grid main content */}

      {/* Dynamic Status Bar: Small feedback area at the bottom */}
      <footer className="glass-footer"> {/* Minimal footer bar */}
        <div className="status-dot animate-pulse"></div> {/* Pulse indicator for live connection */}
        <p className="status-text">Live Sync Active • {new Date().toLocaleTimeString()}</p> {/* Connection status and time */}
      </footer> {/* End of footer */}

    </div> // End of application root div
  );
}

export default App; // Export the AtmosSync dashboard as the primary application component

