            {newsData.map((article, idx) => ( // Map through the top news articles from state
              <div key={idx} className="news-item"> {/* Individual news entry with title and source */}
                <p className="news-title">{article.title}</p> {/* Article headline text */}
                <span className="news-source">{article.source.name}</span> {/* Name of the news publisher */}
              </div> // End of news entry
            ))}
