      <footer className="glass-footer"> {/* Minimal footer bar */}
        <div className="status-dot animate-pulse"></div> {/* Pulse indicator for live connection */}
        <p className="status-text">Live Sync Active • {new Date().toLocaleTimeString()}</p> {/* Connection status and time */}
      </footer> {/* End of footer */}

    </div> // End of application root div
  );
}

export default App; // Export the AtmosSync dashboard as the primary application component

