                <p className="weather-desc">{weatherData.weather[0].description}</p>
              </div>
            </div>
            <div className="weather-stats">
              <div className="stat"><span>Humidity</span><strong>{weatherData.main.humidity}%</strong></div>
              <div className="stat"><span>Wind</span><strong>{weatherData.wind.speed} m/s</strong></div>
              <div className="stat"><span>Pressure</span><strong>{weatherData.main.pressure} hPa</strong></div>
            </div>
          </section>
        )}

        <section className="glass-card forecast-card">
          <h3 className="section-title">5-Day Forecast</h3>
          <div className="forecast-scroll">
            {forecastData?.list?.slice(0, 5).map((item: any, idx: number) => (
              <div key={idx} className="forecast-item">
                <span className="forecast-time">{new Date(item.dt * 1000).getHours()}:00</span>
                <span className="forecast-icon">{getWeatherIcon(item.weather[0].description)}</span>
                <span className="forecast-temp">{Math.round(item.main.temp)}°</span>
              </div>
            ))}
          </div>
        </section>

        {/* Dedicated Celestial Hub Card */}
        {weatherData?.astro && (
          <section className="glass-card astro-card">
            <h3 className="section-title">Celestial Hub</h3>
            <div className="astro-grid">
              <div className="astro-row"><span className="material-symbols-outlined">sunrise</span><span>Rise: <strong>{weatherData.astro.sunrise}</strong></span></div>
              <div className="astro-row"><span className="material-symbols-outlined">sunset</span><span>Set: <strong>{weatherData.astro.sunset}</strong></span></div>
              <div className="moon-narrative"><p>{weatherData.astro.moon_status}</p></div>
            </div>
          </section>
        )}

        {/* Currency Hub - Naira Base */}
        {exchangeData && (
          <section className="glass-card exchange-card">
            <h3 className="section-title">Currency Hub (NGN Base)</h3>
            <div className="exchange-list">
              <div className="currency-row"><span>USD</span><strong>${exchangeData.conversion_rates.USD.toFixed(5)}</strong></div>
              <div className="currency-row"><span>EUR</span><strong>€{exchangeData.conversion_rates.EUR.toFixed(5)}</strong></div>
              <div className="currency-row"><span>GBP</span><strong>£{exchangeData.conversion_rates.GBP.toFixed(5)}</strong></div>
            </div>
          </section>
        )}

        <section className="glass-card news-card">
          <h3 className="section-title">World Intel</h3>
          <div className="news-feed">
            {newsData.map((article, idx) => (
              <div key={idx} className="news-item">
                <p className="news-title">{article.title}</p>
                <span className="news-source">{article.source.name}</span>
              </div>
            ))}
          </div>
        </section>
      </main>
    </div>
  );
}

export default App;
```

