        fetch(`http://localhost:8000/news`), // Fetch curated news intel
        fetch(`http://localhost:8000/exchange-rate?base=NGN`) // Fetch Naira-based currency conversions
      ]);

      // Update state with parsed JSON responses
      setWeatherData(await weatherRes.json()); // Persist weather/astro
      setForecastData(await forecastRes.json()); // Persist forecast
      setNewsData((await newsRes.json()).articles?.slice(0, 3) || []); // Persist top 3 news stories for UI balance
